members.default:
function(params) {
            let template = this;
            let keys = template.match(/\{{.*?\}}/g);

            if(keys) {
                for (let key of keys) {
                    let cleanKey = key.replace('{{', '').replace('}}', '');
                    let val = '';

                    cleanKey.split('.').forEach(k => {
                        val = (val == '') ?  params[k] : val[k];
                    });

                    template = template.replace(key, val);
                }
            }
            return template;
        }
